+
+    fn internal(&self) -> FtsEntryInternal {
+        FtsEntryInternal {
+            path: self.path.clone(),
+            level: self.level,
+            follow_symlink: self.follow_symlink,
+            instr: self.entry().fts_instr,
+            visit: self.visit,
